-- Radpro TLD Monitoring - PostgreSQL schema notes
-- The migration script creates tables dynamically from the SQLite schema to preserve
-- exact camelCase column names used by the existing application.
--
-- Recommended PostgreSQL extensions for production:
CREATE EXTENSION IF NOT EXISTS pgcrypto;
